 * Modular exponentiation: (base^exp) % mod
 * Uses BigInt for safety with large numbers.
 */
function power(base, exp, mod) {
    let res = 1n;
    let b = BigInt(base) % BigInt(mod);
    let e = BigInt(exp);
    let m = BigInt(mod);

    while (e > 0n) {
        if (e % 2n === 1n) {
            res = (res * b) % m;
        }
        b = (b * b) % m;
        e /= 2n;
    }
    return Number(res);
}

function solve(nums1, nums0) {
    const MOD = 1000000007;
    const N = nums1.length;

    // 1. Combine and store segment data
    const segments = [];
    for (let i = 0; i < N; i++) {
        segments.push({
            n1: nums1[i],
            n0: nums0[i]
        });
    }

    // 2. Custom Sort
    // Sort segments such that S_A S_B >= S_B S_A lexicographically.
    // Criterion: Prefer higher n1. If n1 are equal, prefer lower n0.
    segments.sort((A, B) => {
        // Sort by n1 descending
        if (A.n1 !== B.n1) {
            return B.n1 - A.n1;
        }

        // If n1 are equal, sort by n0 ascending
        return A.n0 - B.n0;
    });

    // 3. Calculate the final value modulo MOD
    let totalValue = 0;

    for (const segment of segments) {
        const n1 = segment.n1;
        const n0 = segment.n0;
        const L = n1 + n0;

        // Calculate V(S_i) = (2^n1 - 1) * 2^n0 mod MOD

        // Calculate 2^n1 mod MOD
        let p1 = power(2, n1, MOD);

        // Calculate (2^n1 - 1) mod MOD
        // Ensure positive result after subtraction
        let p1_minus_1 = (p1 - 1 + MOD) % MOD;

        // Calculate 2^n0 mod MOD
        let p2 = power(2, n0, MOD);

        // V(S_i) mod MOD
        let V_Si = (p1_minus_1 * p2) % MOD;

        // Update totalValue: totalValue = (totalValue * 2^L + V(S_i)) mod MOD

        // Calculate 2^L mod MOD
        let pL = power(2, L, MOD);

        // Perform calculation using BigInt to prevent overflow during multiplication
        let currentTotalValueBigInt = BigInt(totalValue);
        let pLBigInt = BigInt(pL);
        let V_SiBigInt = BigInt(V_Si);
        let MODBigInt = BigInt(MOD);

        // totalValue * 2^L mod MOD
        let shifted_value = (currentTotalValueBigInt * pLBigInt) % MODBigInt;

        // Add V(S_i) mod MOD
        let newTotalValue = (shifted_value + V_SiBigInt) % MODBigInt;

        totalValue = Number(newTotalValue);
    }

    return totalValue;
