fun power(base: Long, exp: Long, mod: Long): Long {
    var res = 1L
    var b = base % mod
    var e = exp

    while (e > 0) {
        if (e % 2 == 1L) {
            // (res * b) % mod. Since mod is 10^9+7, the product fits in Long.
            res = (res * b) % mod
        }
        b = (b * b) % mod
        e /= 2
    }
    return res
}

data class Segment(val n1: Long, val n0: Long) : Comparable<Segment> {
    override fun compareTo(other: Segment): Int {
        // Sort segments such that A comes before B if A > B lexicographically.
        // Criterion: Prefer higher n1. If n1 are equal, prefer lower n0.

        if (this.n1 != other.n1) {
            // Higher n1 comes first (Descending order for n1)
            return other.n1.compareTo(this.n1)
        }

        // If n1 are equal, lower n0 comes first (Ascending order for n0)
        return this.n0.compareTo(other.n0)
    }
}

